import{_ as a,a as d,b as t,c as i,d as o,e as n,f as s,g as l}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as r,o as p,c,a2 as u}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/federated-distributed-index.md","filePath":"bn-BD/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"bn-BD/Other/federated-distributed-index.md"};function b(m,e,f,g,x,y){return p(),c("div",null,[...e[0]||(e[0]=[u('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index একাধিক ImgBed site-কে একে অন্যের সঙ্গে file lists share করতে দেয়।</p><p>সহজভাবে:</p><ul><li>আপনার site-এর selected folders অন্যদের সঙ্গে share করতে পারেন।</li><li>অন্য node-এ join করে সেই node-এর shared file list আপনার admin panel-এ sync করতে পারেন।</li><li>Federated files মূলত browsing, searching এবং links খোলার জন্য। এগুলো আপনার own storage-এ re-upload হয় না।</li></ul><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>খুলুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>Page-এ তিনটি tabs আছে:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>নিজের node enable, public domain confirm, shared folders select এবং outbound index update</td></tr><tr><td>Nodes I Joined</td><td>আপনি যে অন্য ImgBed nodes join করেছেন সেগুলো manage</td></tr><tr><td>Nodes Joining Me</td><td>যারা আপনার node join করতে চায় তাদের requests manage</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Local Node</code> খুলুন।</li><li><code>Enable</code> on করুন।</li><li><code>Sync folders</code>-এর নিচে share করার folders নির্বাচন করুন।</li><li><code>Update Outbound Index</code> ক্লিক করুন।</li><li>ImgBed domain change detect করলে current domain সঠিক কি না confirm করে এগোন।</li></ol><p>Multiple sync folders select করা যায়।</p><p>Sync folder list empty থাকলে সব folders share হবে।</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain হলো আপনার node access করতে অন্য nodes যে site URL ব্যবহার করে।</p><p>ImgBed এটি automatically detect করে। Manually type করতে হয় না। প্রথমবার index update করলে ImgBed জিজ্ঞেস করে current access URL production domain কি না।</p><p>পরে domain বদলালে index update করার সময় আবার confirmation চাইবে।</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders ঠিক করে federation nodes-এর সঙ্গে কোন files share হবে।</p><p>যেমন, শুধু এগুলো select করলে:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>অন্য nodes শুধু এই দুই directories-এর files দেখতে পাবে।</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>এটি অন্য nodes আপনার কাছ থেকে যে file list sync করতে পারে সেটি update করে।</p><p>ব্যবহার করুন যখন:</p><ul><li>প্রথমবার federation enable করছেন।</li><li>Share করতে চান এমন files upload করেছেন।</li><li>Sync folders বদলেছেন।</li><li>Public domain বদলেছেন এবং confirm করতে হবে।</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> হলো অন্য nodes subscribe করার জায়গা।</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="অন্য-node-join-করার-request" tabindex="-1">অন্য Node Join করার Request <a class="header-anchor" href="#অন্য-node-join-করার-request" aria-label="Permalink to &quot;অন্য Node Join করার Request&quot;">​</a></h3><ol><li>অন্য owner-এর কাছ থেকে invitation link নিন।</li><li>Input box-এ paste করুন।</li><li><code>Request to Join</code> ক্লিক করুন।</li><li>অন্য owner admin panel থেকে approve করা পর্যন্ত অপেক্ষা করুন।</li></ol><p>Approval-এর পর node status approved হয়।</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> joined nodes থেকে file lists sync করে।</p><p>ব্যবহার করুন যখন:</p><ul><li>অন্য owner সদ্য আপনার request approve করেছে।</li><li>অন্য owner জানিয়েছে shared content update হয়েছে।</li><li>সব joined federation file lists refresh করতে চান।</li></ul><p>শুধু এক node update করতে node card-এর <code>Update Index</code> ক্লিক করুন।</p><p><img src="'+t+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>কোনো node আর sync করতে না চাইলে <code>Unsubscribe</code> ক্লিক করুন।</p><p>Unsubscribe করার পর সেই node-এর federated index আপনার local site থেকে সরানো হয়।</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> হলো অন্যদের requests handle করার জায়গা।</p><p><img src="'+i+'" alt="Nodes joining me" loading="lazy"></p><h3 id="invitation-link-generate-করা" tabindex="-1">Invitation Link Generate করা <a class="header-anchor" href="#invitation-link-generate-করা" aria-label="Permalink to &quot;Invitation Link Generate করা&quot;">​</a></h3><ol><li>Local node enabled কি না নিশ্চিত করুন।</li><li><code>Update Outbound Index</code> অন্তত একবার ক্লিক করুন, যাতে ImgBed public domain confirm করে।</li><li><code>Nodes Joining Me</code> খুলুন।</li><li><code>Reset Invitation Link</code> ক্লিক করুন।</li><li>Invitation link copy করে অন্য owner-কে পাঠান।</li></ol><p>Invitation link empty হলে সাধারণত public domain confirm হয়নি। <code>Local Node</code>-এ ফিরে <code>Update Outbound Index</code> ক্লিক করুন।</p><h3 id="join-requests-handle-করা" tabindex="-1">Join Requests Handle করা <a class="header-anchor" href="#join-requests-handle-করা" aria-label="Permalink to &quot;Join Requests Handle করা&quot;">​</a></h3><p>কেউ request submit করলে সেটি <code>Nodes Joining Me</code> list-এ দেখা যায়।</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>অন্য node-কে আপনার shared file list sync করতে দেয়</td></tr><tr><td>Reject</td><td>Join request refuse করে</td></tr><tr><td>Delete</td><td>Finished record সরায়</td></tr><tr><td>Check Status</td><td>অন্য side এখনও এই relationship রাখে কি না check করে</td></tr></tbody></table><p>Approval-এর পরও অন্য side-কে <code>Update Inbound Index</code> ক্লিক করতে হবে, তারপর আপনার shared files সেখানে দেখা যাবে।</p><p><img src="'+o+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>Relationship approve হলে node card-এর <code>Message</code> ক্লিক করুন।</p><p>Messages শুধু federation relationship নিয়ে communication-এর জন্য। এগুলো files, tags, directories বা permissions বদলায় না।</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="federated-files-দেখা" tabindex="-1">Federated Files দেখা <a class="header-anchor" href="#federated-files-দেখা" aria-label="Permalink to &quot;Federated Files দেখা&quot;">​</a></h2><p>Sync complete হলে admin file list-এ ফিরে যান।</p><p>Page-এর top-এ local files এবং federated files-এর মধ্যে switch করুন। Federated files-এ synced content browse করা যায়।</p><p>Federated files মূলত viewing, searching, previewing এবং links copy করার জন্য। এগুলো local files নয়, তাই নিজের site থেকে move, delete, retag বা backup করা যায় না।</p><p><img src="'+s+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="no-relationship-record-বলে-reapply-করতে-বলছে-কেন" tabindex="-1">No Relationship Record বলে Reapply করতে বলছে কেন? <a class="header-anchor" href="#no-relationship-record-বলে-reapply-করতে-বলছে-কেন" aria-label="Permalink to &quot;No Relationship Record বলে Reapply করতে বলছে কেন?&quot;">​</a></h3><p>সাধারণত এর মানে অন্য side আপনাকে delete করে record সরিয়েছে, তাই relationship আর পাওয়া যাচ্ছে না। নতুন join request submit করুন।</p><p><img src="'+l+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="join-করার-পর-files-দেখছি-না-কেন" tabindex="-1">Join করার পর Files দেখছি না কেন? <a class="header-anchor" href="#join-করার-পর-files-দেখছি-না-কেন" aria-label="Permalink to &quot;Join করার পর Files দেখছি না কেন?&quot;">​</a></h3><p>Check করুন:</p><ol><li>অন্য owner আপনার request approve করেছে।</li><li>অন্য owner <code>Update Outbound Index</code> ক্লিক করেছে।</li><li>আপনি <code>Update Inbound Index</code> ক্লিক করেছেন।</li><li>অন্য owner-এর sync folders-এ share করতে চাওয়া directories আছে।</li></ol><h3 id="domain-change-detected-হলে-কী-করব" tabindex="-1">Domain Change Detected হলে কী করব? <a class="header-anchor" href="#domain-change-detected-হলে-কী-করব" aria-label="Permalink to &quot;Domain Change Detected হলে কী করব?&quot;">​</a></h3><p>আপনি যদি production domain দিয়ে admin panel খুলে থাকেন, confirm করে continue করুন।</p><p>Temporary address ব্যবহার করলে cancel করুন, production domain দিয়ে admin panel আবার খুলুন, তারপর try করুন।</p><h3 id="empty-sync-folder-list-মানে-কী" tabindex="-1">Empty Sync Folder List মানে কী? <a class="header-anchor" href="#empty-sync-folder-list-মানে-কী" aria-label="Permalink to &quot;Empty Sync Folder List মানে কী?&quot;">​</a></h3><p>Empty sync folder list মানে সব folders share হবে।</p><p>শুধু কিছু directories share করতে চাইলে manually সেই folders select করুন।</p><h3 id="outbound-এবং-inbound-index-updates-এর-পার্থক্য" tabindex="-1">Outbound এবং Inbound Index Updates-এর পার্থক্য <a class="header-anchor" href="#outbound-এবং-inbound-index-updates-এর-পার্থক্য" aria-label="Permalink to &quot;Outbound এবং Inbound Index Updates-এর পার্থক্য&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>অন্যরা আমার কাছ থেকে যা sync করতে পারে তা update করে</td></tr><tr><td>Update Inbound Index</td><td>আমি অন্যদের কাছ থেকে যা sync করেছি তা update করে</td></tr></tbody></table>',78)])])}const _=r(h,[["render",b]]);export{k as __pageData,_ as default};
